import{_ as o,o as a,c as r,ae as n}from"./chunks/framework.C8MNLDzb.js";const d=JSON.parse('{"title":"左传典故","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/diangu/jing/左传.md","filePath":"docs/sucai/diangu/jing/左传.md"}'),s={name:"docs/sucai/diangu/jing/左传.md"};function e(g,t,u,i,h,q){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="左传典故" tabindex="-1">左传典故 <a class="header-anchor" href="#左传典故" aria-label="Permalink to &quot;左传典故&quot;">​</a></h1><h2 id="曹刿论战" tabindex="-1">曹刿论战 <a class="header-anchor" href="#曹刿论战" aria-label="Permalink to &quot;曹刿论战&quot;">​</a></h2><p><strong>典故：</strong> 齐国攻打鲁国，曹刿请求面见鲁庄公。曹刿问鲁庄公凭什么作战，庄公说：&quot;衣食所安，弗敢专也，必以分人。&quot;曹刿说：&quot;小惠未遍，民弗从也。&quot;庄公又说：&quot;牺牲玉帛，弗敢加也，必以信。&quot;曹刿说：&quot;小信未孚，神弗福也。&quot;庄公最后说：&quot;小大之狱，虽不能察，必以情。&quot;曹刿说：&quot;忠之属也，可以一战。&quot; <strong>出处：</strong> 《左传·庄公十年》 <strong>释义：</strong> &quot;一鼓作气&quot;出自此典，比喻趁气势正盛时一举取胜。后用&quot;曹刿论战&quot;指代以弱胜强的经典战例。</p><h2 id="退避三舍" tabindex="-1">退避三舍 <a class="header-anchor" href="#退避三舍" aria-label="Permalink to &quot;退避三舍&quot;">​</a></h2><p><strong>典故：</strong> 晋公子重耳流亡楚国时，楚成王问他：&quot;你将来回到晋国，拿什么报答我？&quot;重耳说：&quot;若以君之灵，得反晋国，晋楚治兵，遇于中原，其辟君三舍。&quot;后来重耳回到晋国即位，是为晋文公。城濮之战中，晋文公果然命令军队退避三舍（九十里），以报当年楚王之恩。 <strong>出处：</strong> 《左传·僖公二十三年》《左传·僖公二十八年》 <strong>释义：</strong> 比喻对人让步或回避，不敢竞争。</p><h2 id="弦高犒师" tabindex="-1">弦高犒师 <a class="header-anchor" href="#弦高犒师" aria-label="Permalink to &quot;弦高犒师&quot;">​</a></h2><p><strong>典故：</strong> 秦军偷袭郑国，行至滑国时，被郑国商人弦高发现。弦高一面派人回国报信，一面以十二头牛犒劳秦军，假装郑国早已有备。秦军以为郑国有防备，遂撤军而去。 <strong>出处：</strong> 《左传·僖公三十三年》 <strong>释义：</strong> 形容临危不惧，以智谋保护国家利益。</p><h2 id="季札观乐" tabindex="-1">季札观乐 <a class="header-anchor" href="#季札观乐" aria-label="Permalink to &quot;季札观乐&quot;">​</a></h2><p><strong>典故：</strong> 吴国公子季札出使鲁国，鲁国乐师为他演奏周南、召南及各国民歌，季札一一加以评论，从音乐中预知各国政治兴衰，无不切中要害。 <strong>出处：</strong> 《左传·襄公二十九年》 <strong>释义：</strong> 形容精通音律能从音乐中洞察世事，后也借指欣赏文艺作品。</p><h2 id="郑伯克段于鄢" tabindex="-1">郑伯克段于鄢 <a class="header-anchor" href="#郑伯克段于鄢" aria-label="Permalink to &quot;郑伯克段于鄢&quot;">​</a></h2><p><strong>典故：</strong> 郑庄公出生时脚先出来，使其母姜氏受惊，故取名&quot;寤生&quot;，姜氏厌恶他而宠爱弟弟段。庄公继位后，姜氏为段请封制邑，庄公不许，只许封京。段不断扩张势力，庄公待机伐之，段逃至鄢，庄公伐鄢，段出奔共国。 <strong>出处：</strong> 《左传·隐公元年》 <strong>释义：</strong> 记叙郑庄公与其弟共叔段争权夺利的斗争，&quot;多行不义必自毙&quot;出自此典。</p><h2 id="卫懿公好鹤" tabindex="-1">卫懿公好鹤 <a class="header-anchor" href="#卫懿公好鹤" aria-label="Permalink to &quot;卫懿公好鹤&quot;">​</a></h2><p><strong>典故：</strong> 卫懿公喜欢鹤，给鹤封官赐禄，出游时让鹤拉车。狄人入侵，士兵们说：&quot;让鹤去打吧，鹤有官爵俸禄。&quot;结果卫军大败，懿公被狄人杀死。 <strong>出处：</strong> 《左传·闵公二年》 <strong>释义：</strong> 比喻玩物丧志，因小失大，或讽刺用人不当。</p><h2 id="晋公子重耳流亡" tabindex="-1">晋公子重耳流亡 <a class="header-anchor" href="#晋公子重耳流亡" aria-label="Permalink to &quot;晋公子重耳流亡&quot;">​</a></h2><p><strong>典故：</strong> 晋献公听信骊姬谗言，逼迫公子重耳流亡在外十九年。重耳流亡期间历经狄、卫、齐、曹、宋、郑、楚、秦等国，受尽冷遇与磨难，最终在秦穆公帮助下回国夺取政权，是为晋文公。 <strong>出处：</strong> 《左传·僖公二十三年》 <strong>释义：</strong> 形容人在困境中历经磨砺，终成大器。</p><h2 id="介子推割股奉君" tabindex="-1">介子推割股奉君 <a class="header-anchor" href="#介子推割股奉君" aria-label="Permalink to &quot;介子推割股奉君&quot;">​</a></h2><p><strong>典故：</strong> 重耳流亡期间，粮食断绝，介子推割下自己腿上的肉煮汤给重耳吃。重耳回国即位后赏赐随从，介子推不愿争功，带着母亲隐居绵山。晋文公烧山想逼他出来，介子推抱树而死。 <strong>出处：</strong> 《左传·僖公二十四年》 <strong>释义：</strong> 形容不计得失、功成不居的忠臣义气。&quot;寒食节&quot;由此而来。</p><h2 id="蹇叔哭师" tabindex="-1">蹇叔哭师 <a class="header-anchor" href="#蹇叔哭师" aria-label="Permalink to &quot;蹇叔哭师&quot;">​</a></h2><p><strong>典故：</strong> 秦穆公派兵袭郑，蹇叔极力反对，认为劳师袭远必败。秦穆公不听，派人伐郑。蹇叔哭着说：&quot;晋人御师必于崤。&quot;后来晋军在崤山伏击秦军，大败秦师。 <strong>出处：</strong> 《左传·僖公三十二年》 <strong>释义：</strong> 比喻有远见之人预见祸患却无法阻止。</p><h2 id="楚庄王问鼎" tabindex="-1">楚庄王问鼎 <a class="header-anchor" href="#楚庄王问鼎" aria-label="Permalink to &quot;楚庄王问鼎&quot;">​</a></h2><p><strong>典故：</strong> 楚国攻打陆浑之戎，陈兵洛阳。楚庄王故意炫耀武力，向周大夫王孙满问九鼎之大小轻重。九鼎是王权的象征，王孙满说：&quot;在德不在鼎。&quot; <strong>出处：</strong> 《左传·宣公三年》 <strong>释义：</strong> &quot;问鼎&quot;比喻图谋夺取政权或有非分之想。</p><h2 id="邲之战" tabindex="-1">邲之战 <a class="header-anchor" href="#邲之战" aria-label="Permalink to &quot;邲之战&quot;">​</a></h2><p><strong>典故：</strong> 晋楚两国在邲地开战。晋军主将荀林父指挥失误，楚军趁机进攻，晋军大败。晋军溃逃时战车陷入泥沼，楚军追击，晋军战车纷纷覆没。 <strong>出处：</strong> 《左传·宣公十二年》 <strong>释义：</strong> 形容因指挥不当而导致的惨败。</p><h2 id="晏子使楚" tabindex="-1">晏子使楚 <a class="header-anchor" href="#晏子使楚" aria-label="Permalink to &quot;晏子使楚&quot;">​</a></h2><p><strong>典故：</strong> 晏子出使楚国，楚人因其身材矮小，从小门入以羞辱他。晏子说：&quot;使狗国者，从狗门入。今臣使楚，不当从此门入。&quot;楚王设宴，又让人押着盗贼从堂下过，说是齐国人。晏子说：&quot;橘生淮南则为橘，生于淮北则为枳，齐人在楚为盗，楚之水土使民善盗。&quot; <strong>出处：</strong> 《左传·昭公三年》（注：晏子事迹主要见《晏子春秋》） <strong>释义：</strong> 形容外交辞令机智巧妙，以弱胜强。</p>',25)])])}const c=o(s,[["render",e]]);export{d as __pageData,c as default};
